+    };
+    let source_ptr = if input.null_source {
+        std::ptr::null()
+    } else {
+        path.as_ptr()
+    };
+    let fs_ptr = if input.null_fs {
+        std::ptr::null()
+    } else {
+        fs.as_ptr()
+    };
+    let key_ptr = if input.null_key {
+        std::ptr::null()
+    } else {
