+        }
+        7 => {
+            let rc = unsafe {
+                move_mount(
+                    dirfd(input.dirfd_kind),
+                    path_ptr,
+                    -1,
+                    std::ptr::null(),
+                    input.flags,
+                )
+            };
+            assert_unit_rc(input.op % 9, rc);
+        }
+        _ => {
+            let rc = unsafe { mount_setattr(-1, path_ptr, input.flags, attr_ptr, attr.len()) };
+            assert_unit_rc(input.op % 9, rc);
+        }
+    }
+});

